#include <iostream>
#include <string>

class Vehicle {
    int m_speed{};
public:
    Vehicle(int speed) : m_speed{speed} {}
    int getSpeed() const { return m_speed; }
};

class Car : public Vehicle {
    std::string m_name{};
public:
    Car(std::string name, int speed)
        : Vehicle{speed}, m_name{std::move(name)} {}
    void print() const {
        std::cout << m_name << ": " << getSpeed() << " km/h\n";
    }
};

int main()
{
    std::string name{};
    int speed{};
    while (std::cin >> name >> speed)
    {
        Car car{name, speed};
        car.print();
    }
    return 0;
}

