solution_code:
#include <iostream>
#include <string>

class Creature {
    std::string m_name;
public:
    Creature(std::string name) : m_name{std::move(name)} {}
    const std::string& getName() const { return m_name; }
};

class Monster : public Creature {
    int m_health{};
public:
    Monster(std::string name, int health)
        : Creature{std::move(name)}, m_health{health} {}
    int getHealth() const { return m_health; }
};

class BossMonster : public Monster {
    int m_armor{};
public:
    BossMonster(std::string name, int health, int armor)
        : Monster{std::move(name), health}, m_armor{armor} {}
    void print() const {
        std::cout << getName() << " ["
                  << getHealth() << " hp, "
                  << m_armor << " armor] -> "
                  << getHealth() + m_armor << " effective\n";
    }
};

int main()
{
    int n{};
    std::cin >> n;
    for (int i{0}; i < n; ++i)
    {
        std::string name{};
        int health{};
        int armor{};
        std::cin >> name >> health >> armor;

        BossMonster boss{name, health, armor};
        boss.print();
    }
    return 0;
}
